import { useEffect, useState } from "react";
import axios from "axios";

export default function LabourDashboard() {

  const user = JSON.parse(localStorage.getItem("user"));

  const [requests, setRequests] = useState([]);
  const [price, setPrice] = useState("");

  useEffect(() => {
    fetchRequests();
  }, []);

  const fetchRequests = async () => {
    try {
      const res = await axios.get(
        `http://localhost:5000/api/request/labour/${user._id}`
      );
      setRequests(res.data);
    } catch (err) {
      console.log(err);
    }
  };

  // ACCEPT
  const acceptRequest = async (id) => {
    try {
      await axios.put(
        `http://localhost:5000/api/request/labour-response/${id}`,
        {
          price: price || 0,
          action: "accepted"
        }
      );

      fetchRequests();

    } catch (err) {
      console.log(err);
    }
  };

  // REJECT
  const rejectRequest = async (id) => {
    try {
      await axios.put(
        `http://localhost:5000/api/request/labour-response/${id}`,
        {
          price: 0,
          action: "rejected"
        }
      );

      fetchRequests();

    } catch (err) {
      console.log(err);
    }
  };

  return (
    <div style={styles.page}>

      <h2 style={styles.title}>Labour Dashboard</h2>

      <div style={styles.grid}>

        {requests.map((req) => (
          <div key={req._id} style={styles.card}>

            <h3>{req.workType}</h3>

            <p><b>Customer:</b> {req.customerName}</p>
            <p><b>Date:</b> {req.date}</p>
            <p><b>Location:</b> {req.location}</p>

            {/* STATUS */}
            <p>
              <b>Status:</b>{" "}
              <span
                style={{
                  color:
                    req.status === "accepted"
                      ? "green"
                      : req.status === "rejected"
                      ? "red"
                      : "#f59e0b"
                }}
              >
                {req.status}
              </span>
            </p>

            {/* PRICE INPUT */}
            {req.status === "pending" && (
              <input
                style={styles.input}
                placeholder="Set your price"
                onChange={(e) => setPrice(e.target.value)}
              />
            )}

            {/* SHOW PRICE AFTER ACCEPT */}
            {req.status === "accepted" && (
              <p><b>Your Price:</b> ₹{req.labourPrice}</p>
            )}

            {/* CUSTOMER DECISION */}
            <p>
              <b>Customer Decision:</b> {req.customerDecision}
            </p>

            {/* ⭐ RATING DISPLAY */}
            {req.isCompleted && (
              <div style={styles.ratingBox}>
                <p>
                  <b>Rating:</b> {"⭐".repeat(req.rating)}
                </p>
                <p>{req.review}</p>
              </div>
            )}

            {/* BUTTONS */}
            {req.status === "pending" && (
              <div style={styles.btnRow}>

                <button
                  style={styles.acceptBtn}
                  onClick={() => acceptRequest(req._id)}
                >
                  Accept
                </button>

                <button
                  style={styles.rejectBtn}
                  onClick={() => rejectRequest(req._id)}
                >
                  Reject
                </button>

              </div>
            )}

          </div>
        ))}

      </div>
    </div>
  );
}

const styles = {

  page: {
    minHeight: "100vh",
    background: "#f4f7fb",
    padding: "30px",
    fontFamily: "Arial"
  },

  title: {
    textAlign: "center",
    marginBottom: "20px",
    color: "#111827"
  },

  grid: {
    display: "grid",
    gridTemplateColumns: "repeat(auto-fit, minmax(260px, 1fr))",
    gap: "20px"
  },

  card: {
    background: "white",
    padding: "20px",
    borderRadius: "14px",
    boxShadow: "0 6px 18px rgba(0,0,0,0.06)"
  },

  input: {
    width: "100%",
    padding: "10px",
    marginTop: "10px",
    borderRadius: "8px",
    border: "1px solid #d1d5db"
  },

  btnRow: {
    display: "flex",
    gap: "10px",
    marginTop: "12px"
  },

  acceptBtn: {
    flex: 1,
    padding: "10px",
    background: "#16a34a",
    color: "white",
    border: "none",
    borderRadius: "8px",
    cursor: "pointer"
  },

  rejectBtn: {
    flex: 1,
    padding: "10px",
    background: "#dc2626",
    color: "white",
    border: "none",
    borderRadius: "8px",
    cursor: "pointer"
  },

  ratingBox: {
    marginTop: "10px",
    padding: "10px",
    background: "#f9fafb",
    borderRadius: "8px"
  }
};
